/// <summary>Retry the operation with exponential backoff, up to <paramref name="maxAttempts"/> times.</summary>
public async Task<T> WithRetryAsync<T>(Func<Task<T>> operation, int maxAttempts)
{
    for (var attempt = 1; ; attempt++)
    {
        try { return await operation(); }
        catch when (attempt < maxAttempts) { await Task.Delay(TimeSpan.FromMilliseconds(100 * Math.Pow(2, attempt))); }
    }
}

